  "claims": [
    {
      "file": "test/transform-html.js",
      "line": 77,
      "description": "New test expects the default '**Table of Contents**' title as the first TOC line, but the fixture readme-with-html-id.md uses bare START/END markers, so determineTitle returns the empty line between them and no title is emitted (first split element is ''), making this test fail — as the analogous readme-with-hX.md test at transform.js:789 confirms."
    },
    {
      "file": "lib/transform.js",
      "line": 43,
      "description": "encodeURI(header.id) does not escape '(' or ')', so an HTML heading whose id contains a paren produces a malformed markdown link like [text](#a)b) that breaks the TOC entry; the slug path avoids this only because GitHub slug generation strips parens."
    }
  ]
}
